    public static function descriptive_features($samples,$sample_rate_hz=1){$values=self::values($samples,'samples',2);$rate=self::positive($sample_rate_hz,'sampleRateHz');$rms=self::rms($values);$crossings=0;for($i=1;$i<count($values);$i++){if(($values[$i-1]<0&&$values[$i]>=0)||($values[$i-1]>=0&&$values[$i]<0)){$crossings++;}}return array('sampleCount'=>count($values),'sampleRateHz'=>$rate,'durationSeconds'=>(count($values)-1)/$rate,'mean'=>self::mean($values),'standardDeviation'=>self::sd($values),'rms'=>$rms,'minimum'=>min($values),'maximum'=>max($values),'peakToPeak'=>max($values)-min($values),'zeroCrossingCount'=>$crossings,'zeroCrossingRate'=>$crossings/(count($values)-1)*$rate,'crestFactor'=>$rms!=0.0?max(array_map('abs',$values))/$rms:0.0);}
