    public static function pearson_correlation($reference,$comparison){list($a,$b)=self::paired($reference,$comparison);$am=self::mean($a);$bm=self::mean($b);$numerator=0.0;$as=0.0;$bs=0.0;foreach($a as $i=>$value){$ad=$value-$am;$bd=$b[$i]-$bm;$numerator+=$ad*$bd;$as+=$ad*$ad;$bs+=$bd*$bd;}$denominator=sqrt($as*$bs);if($denominator==0.0){throw new InvalidArgumentException('Correlation requires non-constant arrays.');}return $numerator/$denominator;}
