    public static function shift_series($reference,$comparison,$lag_samples){list($a,$b)=self::paired($reference,$comparison);$lag=(int)self::finite($lag_samples,'lagSamples');if(abs($lag)>=count($a)-1){throw new InvalidArgumentException('Absolute lag must leave at least two overlapping samples.');}if($lag>0){$aa=array_slice($a,$lag);$bb=array_slice($b,0,-$lag);}elseif($lag<0){$aa=array_slice($a,0,$lag);$bb=array_slice($b,-$lag);}else{$aa=$a;$bb=$b;}return array('lagSamples'=>$lag,'reference'=>array_values($aa),'comparison'=>array_values($bb),'overlapCount'=>count($aa));}
