    public static function interval_summary($intervals){if(!is_array($intervals)||count($intervals)===0){throw new InvalidArgumentException('intervals must contain at least one interval.');}$durations=array();$starts=array();$ends=array();foreach($intervals as $index=>$interval){if(!is_array($interval)){throw new InvalidArgumentException('intervals['.$index.'] must be an object.');}$start=self::finite($interval['startSeconds']??null,'intervals['.$index.'].startSeconds');$end=self::finite($interval['endSeconds']??null,'intervals['.$index.'].endSeconds');if($end<$start){throw new InvalidArgumentException('intervals['.$index.'] ends before it starts.');}$starts[]=$start;$ends[]=$end;$durations[]=$end-$start;}$span=max($ends)-min($starts);$total=array_sum($durations);return array('intervalCount'=>count($intervals),'totalDurationSeconds'=>$total,'meanDurationSeconds'=>self::mean($durations),'minimumDurationSeconds'=>min($durations),'maximumDurationSeconds'=>max($durations),'coveredSpanSeconds'=>$span,'burdenPercent'=>$span>0?$total/$span*100:0.0);}
    public static function annotation_coverage($annotations,$window_start_seconds,$window_end_seconds){if(!is_array($annotations)){throw new InvalidArgumentException('annotations must be an array.');}$start=self::finite($window_start_seconds,'windowStartSeconds');$end=self::finite($window_end_seconds,'windowEndSeconds');if($end<=$start){throw new InvalidArgumentException('windowEndSeconds must exceed windowStartSeconds.');}$clipped=array();$type_counts=array();foreach($annotations as $index=>$annotation){if(!is_array($annotation)){throw new InvalidArgumentException('annotations['.$index.'] must be an object.');}$as=self::finite($annotation['startSeconds']??null,'annotations['.$index.'].startSeconds');$ae=self::finite($annotation['endSeconds']??$as,'annotations['.$index.'].endSeconds');if($ae<$as){throw new InvalidArgumentException('annotations['.$index.'] ends before it starts.');}$cs=max($start,$as);$ce=min($end,$ae);if($ce>$cs){$clipped[]=array($cs,$ce);}$type=(string)($annotation['type']??'note');$type_counts[$type]=($type_counts[$type]??0)+1;}usort($clipped,static fn($a,$b)=>$a[0]<=>$b[0]);$merged=array();foreach($clipped as $interval){if(count($merged)===0||$interval[0]>$merged[count($merged)-1][1]){$merged[]=array($interval[0],$interval[1]);}else{$last=count($merged)-1;$merged[$last][1]=max($merged[$last][1],$interval[1]);}}$covered=0.0;$records=array();foreach($merged as $interval){$covered+=$interval[1]-$interval[0];$records[]=array('startSeconds'=>$interval[0],'endSeconds'=>$interval[1]);}return array('annotationCount'=>count($annotations),'coveredSeconds'=>$covered,'coveragePercent'=>$covered/($end-$start)*100,'typeCounts'=>$type_counts,'mergedIntervals'=>$records);}
